%% P5_Exp02_scale_dependent_NMC_optimization.m
%
% Purpose:
% This script implements the scale-dependent NMC recertification
% optimization under a scaled proxy prediction-error scenario.
%
% It constructs NMC-specific SOH-dependent action-value functions, reads the
% k-dependent residual-error model generated by Part3, applies the NMC
% residual-scaling factor rho, and re-optimizes the SOH-labelling investment
% k*, threshold policy, cost decomposition, action allocation, and
% action-value contribution under each deployment scale.

clear; clc; close all;

set(groot, 'DefaultFigureVisible', 'on');

%% 0. Path configuration
cfg = struct();

script_dir = fileparts(mfilename('fullpath'));
if isempty(script_dir)
 script_dir = pwd;
end

% Project root folder.
cfg.project_root = fileparts(script_dir);

% Part5 folders.
cfg.input_dir = fullfile(script_dir, 'Input');
cfg.output_dir = fullfile(script_dir, 'Output');
cfg.results_dir = fullfile(cfg.output_dir, 'Results');

cfg.figure_root = fullfile(script_dir, 'Figures');
cfg.main_fig_dir = fullfile(cfg.figure_root, 'Main');
cfg.extended_fig_dir = fullfile(cfg.figure_root, 'Extended');

cfg.function_dir = fullfile(script_dir, 'Function');

% Part3 output folder.
cfg.part3_output_dir = fullfile(cfg.project_root, ...
 'Part3_Prediction error extrapolation', ...
 'Output');

% Input files for Part5.
cfg.soh_file = fullfile(cfg.input_dir, 'NMC_SOH_Table.mat');

% Primary residual-error extrapolation model generated by Part3 Exp03.
cfg.residual_file_primary = fullfile(cfg.part3_output_dir, 'Results', 'P3_Exp03_ResidualExtrapolation_Model.mat');

% Legacy fallback path for the previous Part3 output name.
cfg.residual_file_legacy = fullfile(cfg.part3_output_dir, 'Result03_ResidualExtrapolation_Model.mat');

% Primary LFP scale-dependent result generated by Part5 Exp01.
cfg.lfp_result_file_primary = fullfile(cfg.results_dir, 'P5_Exp01_ScaleDependent_LFP_Results.mat');

% Legacy fallback path for the previous LFP scale-effect result name.
cfg.lfp_result_file_legacy = fullfile(cfg.output_dir, 'Result01_ScaleEffect_LFP_Results.mat');

% Main output files generated by Part5 Exp02.
cfg.result_mat = fullfile(cfg.results_dir, 'P5_Exp02_ScaleDependent_NMC_Results.mat');
cfg.workspace_mat = fullfile(cfg.results_dir, 'P5_Exp02_ScaleDependent_NMC_Workspace.mat');
cfg.summary_csv = fullfile(cfg.results_dir, 'P5_Exp02_ScaleDependent_NMC_Summary.csv');
cfg.action_value_csv = fullfile(cfg.results_dir, 'P5_Exp02_ScaleDependent_NMC_ActionValueDecomposition.csv');
cfg.manuscript_summary_csv = fullfile(cfg.results_dir, 'P5_Exp02_ScaleDependent_NMC_ManuscriptValueSummary.csv');
cfg.action_allocation_csv = fullfile(cfg.results_dir, 'ExD05b_NMC_scale_dependent_action_allocation.csv');

cfg.png_resolution = 600;
% Figure files for Main Fig. 5.
cfg.fig05a = fullfile(cfg.main_fig_dir, 'MainFig05a_NMC_per_pack_cost_reduction_decomposition.fig');
cfg.png05a = fullfile(cfg.main_fig_dir, 'MainFig05a_NMC_per_pack_cost_reduction_decomposition.png');

cfg.fig05b = fullfile(cfg.main_fig_dir, 'MainFig05b_NMC_total_cost_breakdown.fig');
cfg.png05b = fullfile(cfg.main_fig_dir, 'MainFig05b_NMC_total_cost_breakdown.png');

cfg.fig05c = fullfile(cfg.main_fig_dir, 'MainFig05c_NMC_action_value_decomposition.fig');
cfg.png05c = fullfile(cfg.main_fig_dir, 'MainFig05c_NMC_action_value_decomposition.png');

% Figure file for Extended Data Fig. 4d.
cfg.fig_ExD04d = fullfile(cfg.extended_fig_dir, 'ExD04d_NMC_scale_dependent_optimal_thresholds.fig');
cfg.png_ExD04d = fullfile(cfg.extended_fig_dir, 'ExD04d_NMC_scale_dependent_optimal_thresholds.png');

% NMC proxy-error scenario setting.
cfg.rho = 0.8;

% Create required local folders.
folder_list = {cfg.input_dir, cfg.output_dir, cfg.results_dir, cfg.figure_root, cfg.main_fig_dir, cfg.extended_fig_dir, cfg.function_dir};
for ii = 1:numel(folder_list)
 if ~exist(folder_list{ii}, 'dir')
 mkdir(folder_list{ii});
 end
end

% Add the local function folder.
if exist(cfg.function_dir, 'dir')
 addpath(cfg.function_dir);
end

if exist('local_build_noise_by_k', 'file') ~= 2
 error('Function local_build_noise_by_k.m was not found in: %s', ...
 cfg.function_dir);
end

% Check the NMC SOH input file.
if ~isfile(cfg.soh_file)
 error('NMC SOH input file not found: %s', cfg.soh_file);
end

% Locate the Part3 residual-error result file.
if isfile(cfg.residual_file_primary)
 cfg.residual_file = cfg.residual_file_primary;
elseif isfile(cfg.residual_file_legacy)
 cfg.residual_file = cfg.residual_file_legacy;
else
 error(['Part3 residual-error extrapolation model file not found.\n' ...
 'Checked:\n%s\n%s\n' ...
 'Please run Part3 Exp03 first to generate the residual-error model.'], ...
 cfg.residual_file_primary, ...
 cfg.residual_file_legacy);
end

% Locate the LFP scale-dependent result file.
if isfile(cfg.lfp_result_file_primary)
 cfg.lfp_result_file = cfg.lfp_result_file_primary;
elseif isfile(cfg.lfp_result_file_legacy)
 cfg.lfp_result_file = cfg.lfp_result_file_legacy;
else

 error(['LFP scale-dependent result file not found.\n' ...
 'Checked:\n%s\n%s\n' ...
 'Please run Part5 Exp01 first to generate the LFP scale-dependent result.'], ...
 cfg.lfp_result_file_primary, ...
 cfg.lfp_result_file_legacy);
end

fprintf('================ Part5 Exp02 scale-dependent NMC optimization ================\n');
fprintf('NMC SOH input file: %s\n', cfg.soh_file);
fprintf('Part3 residual file: %s\n', cfg.residual_file);
fprintf('LFP scale-effect file: %s\n', cfg.lfp_result_file);
fprintf('Output result file: %s\n', cfg.result_mat);
fprintf('Output workspace file: %s\n', cfg.workspace_mat);
fprintf('Summary CSV file: %s\n', cfg.summary_csv);
fprintf('Action-value CSV file: %s\n', cfg.action_value_csv);
fprintf('Manuscript summary CSV: %s\n', cfg.manuscript_summary_csv);
fprintf('Action-allocation CSV: %s\n', cfg.action_allocation_csv);
fprintf('Main figure folder: %s\n', cfg.main_fig_dir);
fprintf('Extended figure folder: %s\n', cfg.extended_fig_dir);

%% 1. Basic physical and economic parameters for NMC

% ===== 1.1 Load the NMC SOH trajectory =====
S_soh = load(cfg.soh_file);

if isfield(S_soh, 'SOH_table')
 if isfield(S_soh, 'day')
 SOH_data = S_soh.SOH_table(1:S_soh.day);
 else
 SOH_data = S_soh.SOH_table(isfinite(S_soh.SOH_table));
 end
else
error('Required variable SOH_table was not found in %s.', cfg.soh_file);
end

SOH_data = SOH_data(:);
SOH_data = SOH_data(isfinite(SOH_data));

% ===== 1.2 General economic parameters =====
Q_pack = 25.3;
r = 0.05;
beta_refurbish = 0.09;

ExchangeRate_RMB_USD = 7.04;
p_high_RMB = 1.1621;
p_low_RMB = 0.2986;

p_high = p_high_RMB / ExchangeRate_RMB_USD; % 0.1651
p_low = p_low_RMB / ExchangeRate_RMB_USD; % 0.0424

c_pack = 300;
c_train = 100;

Eta_1 = 40;
Eta_2 = 40;

C0 = 43;
C1 = 80;
gamma = 3;

Lambda_R = 15;
Lambda_A = 12;

C_A1_extra = 10;
C_A2_extra = 15;

% 1.3 Material and economic parameters for NMC direct recycling
M_pack = 173.25;
Exchange_Rate = 1;

PosAcMass = 0.2314;
PosCCMass = 0.0700;
NegAcMass = 0.1425;
NegCCMass = 0.1700;

M_NMC622 = 96.93;
M_Li2CO3 = 73.89;

Rec_Rate_Cathode = 0.90;
Rec_Rate_Graphite = 0.90;
Rec_Rate_Al = 0.90;
Rec_Rate_Cu = 0.90;

P_NMC622 = 29.17; 
P_Li2CO3 = 27.20; 
P_Graphite = 3.84; 
P_Al = 3.42; 
P_Cu = 14.79; 

C_Degraded = 17.34; 

C_Electricity_direct = 300 * 0.111 / 1000;
C_Labor_direct = 223.79 / 1000;
C_Disassemble_direct = 143.00 / 1000;
C_Equip_direct = 57.57 / 1000;
C_Sewage_direct = 100.29 / 1000;

Fixed_Op_Cost = C_Electricity_direct + C_Labor_direct + ...
 C_Disassemble_direct + C_Equip_direct + C_Sewage_direct;


% 2. SOH-dependent action-value functions for NMC
valid_end_idx = find(SOH_data >= 0.4);
end_idx = valid_end_idx(end);

start_indices = find(SOH_data <= 1.0 & SOH_data >= 0.4);
num_cases = length(start_indices);

a = zeros(num_cases, 1);
V1 = zeros(num_cases, 1);

for k = 1:num_cases
 start_idx = start_indices(k);
 SOH_slice = SOH_data(start_idx:end_idx);

 a(k) = SOH_slice(1);
 days_elapsed = (0:length(SOH_slice)-1)';

 SOH_diff = 1 - SOH_slice;
 Poly_term = -0.2303 .* SOH_diff + 0.9582;

 Daily_Value_Raw = Q_pack .* SOH_slice .* (Poly_term .* p_high - p_low);
 Discount_Factor = 1 ./ ((1 + r) .^ (days_elapsed / 365));
 V1(k) = sum(Daily_Value_Raw .* Discount_Factor);
end

[a, sort_idx] = sort(a);
V1 = V1(sort_idx);

[a, ia] = unique(a, 'last');
V1 = V1(ia);

if max(a) < 1.0
 a_old = a;
 V1_old = V1;
 slope = (V1_old(end) - V1_old(end-1)) / (a_old(end) - a_old(end-1));
 V1_at_1 = V1_old(end) + slope * (1.0 - a_old(end));
 a = [a_old; 1.0];
 V1 = [V1_old; V1_at_1];
end

% A1
calc_V_reuse_base = @(soh) interp1(a, V1, soh, 'linear', 'extrap');
calc_V_reuse = @(soh) calc_V_reuse_base(soh) - C_A1_extra;

% A2
calc_C_refurbish = @(soh) C0 + C1 .* (1 - soh).^gamma;
calc_V_refurbish_base = @(soh) ...
 calc_V_reuse_base(min(soh + beta_refurbish .* (1 - soh), 1.0)) - calc_C_refurbish(soh);
calc_V_refurbish = @(soh) calc_V_refurbish_base(soh) - C_A1_extra - C_A2_extra;

% A3
Base_Y_NMC622 = PosAcMass * Rec_Rate_Cathode;
Base_Y_Graphite = NegAcMass * Rec_Rate_Graphite;
Base_Y_Al = PosCCMass * Rec_Rate_Al;
Base_Y_Cu = NegCCMass * Rec_Rate_Cu;

Y_Li2CO3_in_func = @(soh) (PosAcMass ./ M_NMC622) .* ((1 - soh) ./ 2) .* M_Li2CO3;

calc_V_recycle = @(soh) M_pack .* Exchange_Rate .* ( ...
 (Base_Y_NMC622 .* P_NMC622 + ...
 Base_Y_Graphite .* P_Graphite + ...
 Base_Y_Al .* P_Al + ...
 Base_Y_Cu .* P_Cu) ...
 - (Y_Li2CO3_in_func(soh) .* P_Li2CO3) ...
 - (PosAcMass .* C_Degraded + Fixed_Op_Cost) ...
 );

%% 3. Load k-dependent residual-error extrapolation model

error_model_file = cfg.residual_file;

if ~isfile(error_model_file)
 error('Part3 residual-error model file not found: %s', error_model_file);
end

ErrorModel = load(error_model_file);

required_error_vars = { ...
 'k_emp', ...
 'k_vals', ...
 'err_cell', ...
 'rmse_target', ...
 'w_curve', ...
 'muM_curve', ...
 'sigM_curve', ...
 'muR_curve', ...
 'sigR_curve', ...
 'region', ...
 'cfg'};

for ii = 1:numel(required_error_vars)
 if ~isfield(ErrorModel, required_error_vars{ii})
 error('Required variable "%s" was not found in %s.', ...
 required_error_vars{ii}, error_model_file);
 end
end

k_emp = ErrorModel.k_emp(:);
k_vals = ErrorModel.k_vals(:);
err_cell = ErrorModel.err_cell;

rmse_target = ErrorModel.rmse_target(:);
w_curve = ErrorModel.w_curve(:);
muM_curve = ErrorModel.muM_curve(:);
sigM_curve = ErrorModel.sigM_curve(:);
muR_curve = ErrorModel.muR_curve(:);
sigR_curve = ErrorModel.sigR_curve(:);

region = ErrorModel.region;

if isfield(ErrorModel.cfg, 'k_anchor')
 k_anchor = ErrorModel.cfg.k_anchor;
else
 k_anchor = 21;
end

if isfield(ErrorModel.cfg, 'k_bridge_end')
 k_bridge_end = ErrorModel.cfg.k_bridge_end;
else
 k_bridge_end = 26;
end

if max(k_vals) < 50
 error(['The loaded residual-error model only covers k = %d to %d. ', ...
 'Please rerun P3_Exp03_label_dependent_residual_extrapolation.m with a larger cfg.k_extrap_max.'], ...
 min(k_vals), max(k_vals));
end

if numel(k_vals) ~= numel(rmse_target) || ...
 numel(k_vals) ~= numel(w_curve) || ...
 numel(k_vals) ~= numel(muM_curve) || ...
 numel(k_vals) ~= numel(sigM_curve) || ...
 numel(k_vals) ~= numel(muR_curve) || ...
 numel(k_vals) ~= numel(sigR_curve)
 error('The loaded residual-error model has inconsistent curve lengths.');
end

N_sim = 100000;
rho = cfg.rho;

rng(42);

base_u = rand(N_sim, 1);
base_z = randn(N_sim, 1);
base_pick = rand(N_sim, 1);

fprintf('Residual-error model loaded from: %s\n', error_model_file);
fprintf('Loaded k range: %d to %d\n', min(k_vals), max(k_vals));
fprintf('NMC proxy-error scaling factor rho = %.2f\n', rho);

%% 4. Load deployment-scale list from the LFP scale-effect result

S_lfp = load(cfg.lfp_result_file);

if ~isfield(S_lfp, 'scale_ton_list')
 error('Required variable scale_ton_list was not found in %s.', cfg.lfp_result_file);
end

scale_ton_list = S_lfp.scale_ton_list(:);

N_list_NMC = max(1, round(scale_ton_list * 1000 / M_pack));
num_N = numel(scale_ton_list);

fprintf('Loaded deployment-scale list from LFP result.\n');
fprintf('NMC pack-number range: %d to %d\n', min(N_list_NMC), max(N_list_NMC));

%% 5. Precompute NMC threshold search results for each candidate k
fprintf('>>> Starting NMC scale-effect analysis...\n');


k_unique = k_vals(:);
num_k_use = numel(k_unique);

% Generate true SOH samples and action values once for reuse throughout the script

s_true = 0.4 + 0.6 * rand(N_sim, 1);

% Independent selector for the probability bridge in the residual
% generator. A separate stream preserves the original common-random-number
% sequence used for base_u, base_z, base_pick, and s_true.
bridge_stream = RandStream('mt19937ar', 'Seed', 1043);
base_bridge = rand(bridge_stream, N_sim, 1);

Pi_True = [calc_V_reuse(s_true), calc_V_refurbish(s_true), calc_V_recycle(s_true)];
[Pi_True_Max, True_Action_i] = max(Pi_True, [], 2);

% Optimized thresholds, per-pack average losses, and action ratios under each k
T1_byK_NMC = zeros(num_k_use,1);
T2_byK_NMC = zeros(num_k_use,1);

O_mean_byK_NMC = zeros(num_k_use,1);
A_mean_byK_NMC = zeros(num_k_use,1);
R_mean_byK_NMC = zeros(num_k_use,1);

Action_Ratio_byK_NMC = zeros(num_k_use, 3);
Action_Value_Mean_byK_NMC = zeros(num_k_use, 3);


T1_grid = 0.740 : 0.001 : 0.820;
T2_grid = 0.940 : 0.001 : 1.000;

for ik = 1:num_k_use
 k_current = k_unique(ik);

fprintf(' > Running NMC threshold search for k = %d\n', k_current);

noise_raw = local_build_noise_by_k( ...
 k_current, ...
 k_emp, k_anchor, k_bridge_end, ...
 err_cell, ...
 w_curve, muM_curve, sigM_curve, muR_curve, sigR_curve, rmse_target, k_vals, ...
 base_u, base_z, base_pick, base_bridge);

% Center the inherited LFP-derived residual template before NMC scaling.
eps_k = noise_raw - mean(noise_raw);

sampled_noise = rho .* eps_k;

s_pred = min(max(s_true + sampled_noise, 0), 1.0);

 min_L = inf;
 best_T1 = NaN;
 best_T2 = NaN;
 best_O_mean = NaN;
 best_A_mean = NaN;
 best_R_mean = NaN;
 best_ratio = [NaN, NaN, NaN];
 best_value_mean = [NaN, NaN, NaN];

 for T1 = T1_grid
 for T2 = T2_grid
 if T1 >= T2
 continue;
 end

 Pred_Action_j = 3 * ones(N_sim, 1);
 Pred_Action_j(s_pred >= T1 & s_pred < T2) = 2;
 Pred_Action_j(s_pred >= T2) = 1;

 idx_pred = sub2ind([N_sim, 3], (1:N_sim)', Pred_Action_j);
 O_arr = max(Pi_True_Max - Pi_True(idx_pred), 0);

 is_G1_error = (True_Action_i == 3 & Pred_Action_j == 2) | ...
 (True_Action_i == 2 & Pred_Action_j == 3);
 is_G2_error = (True_Action_i == 1 & Pred_Action_j == 2) | ...
 (True_Action_i == 2 & Pred_Action_j == 1);

 Current_Eta = zeros(N_sim, 1);
 Current_Eta(is_G1_error) = Eta_1;
 Current_Eta(is_G2_error) = Eta_2;

 trigger_penalty = O_arr > Current_Eta;
 Excess_Loss = max(0, O_arr - Current_Eta);

 A_arr = trigger_penalty .* Lambda_A;
 R_arr = (Pred_Action_j < True_Action_i) .* trigger_penalty .* (Lambda_R .* Excess_Loss);

 E_L = mean(O_arr + A_arr + R_arr);

 if E_L < min_L
 min_L = E_L;
 best_T1 = T1;
 best_T2 = T2;

 best_O_mean = mean(O_arr);
 best_A_mean = mean(A_arr);
 best_R_mean = mean(R_arr);

 best_ratio(1) = mean(Pred_Action_j == 1);
 best_ratio(2) = mean(Pred_Action_j == 2);
 best_ratio(3) = mean(Pred_Action_j == 3);

 v_A1 = zeros(N_sim, 1);
 v_A2 = zeros(N_sim, 1);
 v_A3 = zeros(N_sim, 1);

 idx_A1 = (Pred_Action_j == 1);
 idx_A2 = (Pred_Action_j == 2);
 idx_A3 = (Pred_Action_j == 3);

 v_A1(idx_A1) = Pi_True(idx_A1, 1);
 v_A2(idx_A2) = Pi_True(idx_A2, 2);
 v_A3(idx_A3) = Pi_True(idx_A3, 3);

 best_value_mean(1) = mean(v_A1);
 best_value_mean(2) = mean(v_A2);
 best_value_mean(3) = mean(v_A3);
 end
 end
 end

 T1_byK_NMC(ik) = best_T1;
 T2_byK_NMC(ik) = best_T2;

 O_mean_byK_NMC(ik) = best_O_mean;
 A_mean_byK_NMC(ik) = best_A_mean;
 R_mean_byK_NMC(ik) = best_R_mean;

 Action_Ratio_byK_NMC(ik, :) = best_ratio;
 Action_Value_Mean_byK_NMC(ik, :) = best_value_mean;
end

%% 6. Re-optimize NMC k* under each deployment scale

num_k = numel(k_unique);

O_NK_NMC = zeros(num_N, num_k);
A_NK_NMC = zeros(num_N, num_k);
R_NK_NMC = zeros(num_N, num_k);
Model_NK_NMC = zeros(num_N, num_k);
Total_Cost_NK_NMC = zeros(num_N, num_k);

opt_k_idx_NMC = zeros(num_N, 1);
opt_k_NMC = zeros(num_N, 1);
opt_T1_NMC = zeros(num_N, 1);
opt_T2_NMC = zeros(num_N, 1);

opt_O_NMC = zeros(num_N, 1);
opt_A_NMC = zeros(num_N, 1);
opt_R_NMC = zeros(num_N, 1);
opt_Model_NMC = zeros(num_N, 1);
opt_total_cost_NMC = zeros(num_N, 1);

opt_Action_Ratio_NMC = zeros(num_N, 3);

A1_value_NMC = zeros(num_N, 1);
A2_value_NMC = zeros(num_N, 1);
A3_value_NMC = zeros(num_N, 1);

Gross_action_value_NMC = zeros(num_N, 1);
Net_realized_value_NMC = zeros(num_N, 1);
Oracle_action_value_NMC = zeros(num_N, 1);
Net_value_accounting_error_NMC = zeros(num_N, 1);

A1_share_NMC = zeros(num_N, 1);
A2_share_NMC = zeros(num_N, 1);
A3_share_NMC = zeros(num_N, 1);

for iN = 1:num_N

 N_curr = N_list_NMC(iN);

 O_NK_NMC(iN, :) = N_curr .* O_mean_byK_NMC(:)';
 A_NK_NMC(iN, :) = N_curr .* A_mean_byK_NMC(:)';
 R_NK_NMC(iN, :) = N_curr .* R_mean_byK_NMC(:)';
 Model_NK_NMC(iN, :) = k_unique(:)' .* c_pack + c_train;

 Total_Cost_NK_NMC(iN, :) = O_NK_NMC(iN, :) + ...
 A_NK_NMC(iN, :) + ...
 R_NK_NMC(iN, :) + ...
 Model_NK_NMC(iN, :);

 [opt_total_cost_NMC(iN), idx_best] = min(Total_Cost_NK_NMC(iN, :));

 opt_k_idx_NMC(iN) = idx_best;
 opt_k_NMC(iN) = k_unique(idx_best);

 opt_T1_NMC(iN) = T1_byK_NMC(idx_best);
 opt_T2_NMC(iN) = T2_byK_NMC(idx_best);

 opt_O_NMC(iN) = O_NK_NMC(iN, idx_best);
 opt_A_NMC(iN) = A_NK_NMC(iN, idx_best);
 opt_R_NMC(iN) = R_NK_NMC(iN, idx_best);
 opt_Model_NMC(iN) = Model_NK_NMC(iN, idx_best);

 opt_Action_Ratio_NMC(iN, :) = Action_Ratio_byK_NMC(idx_best, :);

 A1_value_NMC(iN) = N_curr * Action_Value_Mean_byK_NMC(idx_best, 1);
 A2_value_NMC(iN) = N_curr * Action_Value_Mean_byK_NMC(idx_best, 2);
 A3_value_NMC(iN) = N_curr * Action_Value_Mean_byK_NMC(idx_best, 3);

 Gross_action_value_NMC(iN) = ...
 A1_value_NMC(iN) + ...
 A2_value_NMC(iN) + ...
 A3_value_NMC(iN);

 % Executed pathway value already contains the opportunity loss.
 % Subtracting opt_total_cost_NMC here would deduct opportunity loss twice.
 Net_realized_value_NMC(iN) = ...
 Gross_action_value_NMC(iN) - ...
 opt_A_NMC(iN) - ...
 opt_R_NMC(iN) - ...
 opt_Model_NMC(iN);

 % Equivalent perfect-information accounting identity.
 Oracle_action_value_NMC(iN) = N_curr * mean(Pi_True_Max);

 net_from_oracle = ...
 Oracle_action_value_NMC(iN) - ...
 opt_O_NMC(iN) - ...
 opt_A_NMC(iN) - ...
 opt_R_NMC(iN) - ...
 opt_Model_NMC(iN);

 Net_value_accounting_error_NMC(iN) = ...
 Net_realized_value_NMC(iN) - net_from_oracle;

 if Gross_action_value_NMC(iN) > 0
 A1_share_NMC(iN) = 100 * A1_value_NMC(iN) / Gross_action_value_NMC(iN);
 A2_share_NMC(iN) = 100 * A2_value_NMC(iN) / Gross_action_value_NMC(iN);
 A3_share_NMC(iN) = 100 * A3_value_NMC(iN) / Gross_action_value_NMC(iN);
 end
end

net_value_tolerance_NMC = max( ...
 1e-6, ...
 1e-10 * max(max(abs(Oracle_action_value_NMC)), 1));

if max(abs(Net_value_accounting_error_NMC)) > net_value_tolerance_NMC
 error(['NMC net-value accounting identity failed. Maximum absolute ' ...
 'difference = %.6g USD.'], ...
 max(abs(Net_value_accounting_error_NMC)));
end

A1_ton_NMC = scale_ton_list .* opt_Action_Ratio_NMC(:, 1);
A2_ton_NMC = scale_ton_list .* opt_Action_Ratio_NMC(:, 2);
A3_ton_NMC = scale_ton_list .* opt_Action_Ratio_NMC(:, 3);

fprintf('>>> NMC scale-effect re-optimization completed.\n');
fprintf('>>> NMC k* range: %d to %d\n', min(opt_k_NMC), max(opt_k_NMC));

