% 6.2 Construct the full NMC scale × k cost matrix for c_pack robustness
nK_full = numel(k_unique);

O_NK_NMC = zeros(num_N, nK_full);
A_NK_NMC = zeros(num_N, nK_full);
R_NK_NMC = zeros(num_N, nK_full);
Model_NK_NMC = zeros(num_N, nK_full);
Total_Cost_NK_NMC = zeros(num_N, nK_full);

T1_by_NK_NMC = zeros(num_N, nK_full);
T2_by_NK_NMC = zeros(num_N, nK_full);

Action_Ratio_NK_NMC = zeros(num_N, nK_full, 3);

for iN = 1:num_N
 N_curr = N_list_NMC(iN);

 for ik = 1:nK_full
 k_curr = k_unique(ik);

% Total decision-loss costs under each k
 O_NK_NMC(iN, ik) = N_curr * O_mean_byK_NMC(ik);
 A_NK_NMC(iN, ik) = N_curr * A_mean_byK_NMC(ik);
 R_NK_NMC(iN, ik) = N_curr * R_mean_byK_NMC(ik);

% Information cost
 Model_NK_NMC(iN, ik) = k_curr * c_pack + c_train;

% Total cost
 Total_Cost_NK_NMC(iN, ik) = ...
 O_NK_NMC(iN, ik) + ...
 A_NK_NMC(iN, ik) + ...
 R_NK_NMC(iN, ik) + ...
 Model_NK_NMC(iN, ik);

% Corresponding thresholds and action ratios
 T1_by_NK_NMC(iN, ik) = T1_byK_NMC(ik);
 T2_by_NK_NMC(iN, ik) = T2_byK_NMC(ik);

 Action_Ratio_NK_NMC(iN, ik, :) = Action_Ratio_byK_NMC(ik, :);
 end
end

